startingCSS:
.scene {
  position: relative;
  height: 280px;
  border-radius: 12px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.bg {
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, #1e1b4b 0%, #0f172a 100%);
}

.blob {
  position: absolute;
  border-radius: 50%;
  filter: blur(1px);
}

.b1 {
  width: 180px;
  height: 180px;
  background: #a855f7;
  top: -40px;
  left: -40px;
  opacity: 0.7;
}

.b2 {
  width: 140px;
  height: 140px;
  background: #3b82f6;
  bottom: -20px;
  right: 60px;
  opacity: 0.7;
}

.b3 {
  width: 100px;
  height: 100px;
  background: #06b6d4;
  top: 30px;
  right: -20px;
  opacity: 0.6;
}

.glass-card {
  position: relative;
  z-index: 1;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 14px;
  padding: 1.75rem 2.5rem;
  color: white;
  text-align: center;
  /* Add backdrop-filter here */
}

.glass-card strong {
  display: block;
  font-size: 1.1rem;
  margin-bottom: 0.5rem;
}

.glass-card p {
  margin: 0;
  font-size: 0.85rem;
  opacity: 0.8;
}
